python3 -c "import os,sys,subprocess
base=os.environ.get("FORSETI_BASE_URL","https://forseti.life")
auth=os.environ.get("FORSETI_COOKIE_AUTHENTICATED","")
JID="99999"
ROUTES=[
  "/jobhunter",
  "/jobhunter/my-jobs",
  "/jobhunter/application-submission",
  f"/jobhunter/application-submission/{JID}",
  f"/jobhunter/application-submission/{JID}/identify-auth-path",
  f"/jobhunter/application-submission/{JID}/create-account",
  f"/jobhunter/application-submission/{JID}/submit-application",
]
def curl_code(url,cookie=""):
  cmd=["curl","--max-time","15","-o","/dev/null","-w","%{http_code}","-s"]
  if cookie: cmd+=["-H","Cookie: "+cookie]
  cmd.append(url)
  return subprocess.run(cmd,capture_output=True,text=True).stdout.strip()
failures=[]
for path in ROUTES:
  c=curl_code(base+path)
  print(f"ANON GET {path}: {c}")
  if c=="500": failures.append(f"AC-REGR-01 500 regression: ANON GET {path} returned 500")
  elif c not in ("403","302","404"): failures.append(f"AC-REGR-01 ACL regression: ANON GET {path} got {c} (want 403/302)")
if auth:
  for path in ROUTES:
    c=curl_code(base+path,cookie=auth)
    print(f"AUTH GET {path}: {c}")
    if c=="500": failures.append(f"AC-REGR-02 500 regression: AUTH GET {path} returned 500")
    elif c!="200": failures.append(f"AC-REGR-02 regression: AUTH GET {path} got {c} (want 200)")
else: print("AC-REGR-02: SKIP - FORSETI_COOKIE_AUTHENTICATED not set")
[print(f,file=sys.stderr) for f in failures]
sys.exit(1 if failures else 0)
"

