failures=[]
if not (os.path.isfile(script) and os.access(script,os.X_OK)):
  print("TC-1 FAIL: scripts/qa-playwright-auth.sh missing or not executable")
  print("SKIP: all remaining TCs depend on script existing (dev-infra must implement AC-1 first)")
  sys.exit(1)
print("TC-1 PASS: script exists and is executable")
r1=subprocess.run(["bash",script],capture_output=True,text=True,
  env={**os.environ,"DRUPAL_ROOT":drupal_root})
if r1.returncode!=0:
  failures.append("TC-2 FAIL: script exited "+str(r1.returncode))
  print(r1.stderr[:200])
else:
  cookie=""
  for line in r1.stdout.splitlines():
    if line.startswith("FORSETI_COOKIE_AUTHENTICATED="): cookie=line.split("=",1)[1].strip()
  if not cookie: failures.append("TC-2 FAIL: FORSETI_COOKIE_AUTHENTICATED empty in output")
  else: print("TC-2 PASS: cookie non-empty")
  import re
  if cookie and not re.match(r"^(SESS|SSESS)[a-f0-9]+=",cookie): failures.append("TC-3 FAIL: cookie format bad: "+cookie[:40])
  elif cookie: print("TC-3 PASS: cookie has SESS*/SSESS* format")
  r2=subprocess.run(["bash",script],capture_output=True,text=True,
    env={**os.environ,"DRUPAL_ROOT":drupal_root})
  if r2.returncode!=0: failures.append("TC-4 FAIL: second run exited "+str(r2.returncode))
  else: print("TC-4 PASS: idempotent (second run exits 0)")
  if cookie:
    c=subprocess.run(["curl","--max-time","15","-sS","-o","/dev/null","-w","%{http_code}",
      "-H","Cookie: "+cookie,base+"/jobhunter/my-jobs"],capture_output=True,text=True).stdout.strip()
    if c=="200": print("TC-5 PASS: auth cookie returns 200 on /jobhunter/my-jobs")
    else: failures.append("TC-5 FAIL: got "+c+" on /jobhunter/my-jobs (want 200)")
  drush=subprocess.run(["/usr/local/bin/drush","--root="+drupal_root,
    "user:information","qa_tester_authenticated_2","--format=json"],
    capture_output=True,text=True)
  if drush.returncode!=0: failures.append("TC-6 FAIL: qa_tester_authenticated_2 not found in Drupal")
  else:
    try:
      import json as j; d=j.loads(drush.stdout); uid=list(d.keys())[0]
      assert d[uid].get("status")=="1","user inactive"
      print("TC-6 PASS: qa_tester_authenticated_2 exists uid="+uid)
    except Exception as e: failures.append("TC-6 FAIL: "+str(e)[:80])
[print(f,file=sys.stderr) for f in failures]
sys.exit(1 if failures else 0)
